<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class RequestAPI { private array|false $headers; private array $payload; private array|bool $permissions = false; private array $route = []; function __construct(array $permissions) { $this->headers = getallheaders(); if ( ($token = $this->headers[TAPMEPPE_UMBRELLA . '-token'] ?? null) && ($token = base64_encode($token)) && isset($permissions[$token]) ) $this->permissions = $permissions[$token]; $piece = ''; $self = explode('/', $_SERVER['PHP_SELF']); $uri = explode('/', $_SERVER['REQUEST_URI']); $length = count($uri); for ($i = 0; $i < $length; $i++) { if (($piece = $uri[$i]) && (!isset($self[$i]) || $piece != $self[$i])) $this->route[] = $piece; } $this->route[count($this->route) - 1] = explode('?', $piece)[0]; $this->payload = [ ...$_GET, ...($_POST ?: json_decode(file_get_contents("php://input"), true) ?: []), ]; } function getHeader(string $key, mixed $fallback = null): mixed { return $this->headers[$key] ?? $fallback; } function getHeaders(): array|false { return $this->headers; } function getPayload(): object { return (object) $this->payload; } function getPermissions(): array|bool|string { return $this->permissions; } function getRoute(): array { return $this->route; } function getRouteAsString(string $separator = '/'): string { return implode($separator, $this->route); } function updatePayload(array $payload): void { $this->payload = $payload; } } 